import{_ as e,C as i,o as p,c as l,j as a,a as t,E as r,ag as d}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"7. 批处理系统：Hive / Spark / Trino","description":"理解 Hive、Spark、Trino 在历史数据加工、分布式计算和跨源分析中的定位。","frontmatter":{"title":"7. 批处理系统：Hive / Spark / Trino","description":"理解 Hive、Spark、Trino 在历史数据加工、分布式计算和跨源分析中的定位。","prev":{"text":"6. ETL / ELT：数据如何进入大数据系统","link":"/chapters/06-etl-elt"},"next":{"text":"8. 实时数据处理：Kafka / Flink","link":"/chapters/08-stream-processing"}},"headers":[],"relativePath":"chapters/07-batch-processing.md","filePath":"chapters/07-batch-processing.md"}'),o={name:"chapters/07-batch-processing.md"};function c(h,s,b,u,k,g){const n=i("Mermaid");return p(),l("div",null,[s[0]||(s[0]=a("h1",{id:"_7-批处理系统-hive-spark-trino",tabindex:"-1"},[t("7. 批处理系统：Hive / Spark / Trino "),a("a",{class:"header-anchor",href:"#_7-批处理系统-hive-spark-trino","aria-label":'Permalink to "7. 批处理系统：Hive / Spark / Trino"'},"​")],-1)),s[1]||(s[1]=a("div",{class:"tip custom-block"},[a("p",{class:"custom-block-title"},"本章导读"),a("p",null,"理解 Hive、Spark、Trino 在历史数据加工、分布式计算和跨源分析中的定位。")],-1)),r(n,{code:"flowchart%20LR%0A%20%20H%5B%22Hive%3A%20%E8%A1%A8%E5%92%8C%E5%85%83%E6%95%B0%E6%8D%AE%22%5D%20--%3E%20S%5B%22Spark%3A%20%E5%A4%A7%E8%A7%84%E6%A8%A1%E8%AE%A1%E7%AE%97%22%5D%0A%20%20S%20--%3E%20T%5B%22Trino%3A%20%E8%B7%A8%E6%BA%90%E4%BA%A4%E4%BA%92%E6%9F%A5%E8%AF%A2%22%5D%0A%20%20H%20--%3E%20F%5B%22Parquet%20%2F%20ORC%20%2F%20Object%20Storage%22%5D%0A%20%20T%20--%3E%20BI%5B%22%E5%88%86%E6%9E%90%E5%92%8C%E6%8E%A2%E7%B4%A2%22%5D%0A"}),s[2]||(s[2]=d(`<p>批处理解决的是历史数据的大规模计算。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>它不追求每条数据毫秒级处理，而是关注在可接受的时间窗口内，把大量历史数据稳定、可重复、可调度地计算出来。</p><p>第 6 章解决了数据如何从 PostgreSQL 进入数仓和湖仓。但数据进入平台后，还要被持续加工：订单明细要清洗，支付和退款要对账，用户日汇总要生成，商品销量排行要重算，历史分区要回填。</p><p>当数据量还小时，这些任务可以在 PostgreSQL 或单机脚本中完成。但当历史数据进入 TB、PB 级，或者任务需要跨很多天、很多表、很多主题域运行时，单机数据库和简单脚本会遇到明显瓶颈：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一次重算要扫描几年历史数据。</span></span>
<span class="line"><span>一个 JOIN 需要处理几十亿行明细。</span></span>
<span class="line"><span>每日任务失败后，需要按分区重跑。</span></span>
<span class="line"><span>一个上游维度变更，会影响大量下游汇总。</span></span>
<span class="line"><span>多个团队同时运行历史分析，资源需要统一调度。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这时需要的不是“更复杂的 SQL”，而是能组织海量文件、分布式计算、任务重跑和跨源查询的批处理体系。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p>批处理回答的是：过去发生了什么，以及这些历史数据如何被加工成可分析、可复用的数据资产。</p></blockquote><p>本章要建立的判断是：批处理系统解决的是大规模历史数据的稳定加工问题。它牺牲毫秒级实时性，换取高吞吐、可重跑、可调度、可追溯和适合大规模历史计算的能力。</p><p>批处理也不是所有问题的答案。它不适合强实时告警、在线交易、点查更新和低延迟交互应用。它更适合离线数仓、历史回算、特征批量生成、报表汇总和数据资产建设。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="_7-1-hive-离线数仓的-sql-入口" tabindex="-1">7.1 Hive：离线数仓的 SQL 入口 <a class="header-anchor" href="#_7-1-hive-离线数仓的-sql-入口" aria-label="Permalink to &quot;7.1 Hive：离线数仓的 SQL 入口&quot;">​</a></h3><p>Hive 的重要性不只在于 Hive SQL，而在于它把大规模文件存储包装成表的方式。</p><p>典型组件包括：</p><ul><li>Hive SQL。</li><li>Hive Metastore。</li><li>内部表 / 外部表。</li><li>分区表 / 桶表。</li><li>Parquet / ORC。</li><li>HDFS / Object Storage。</li></ul><p>Hive 让存储在 HDFS 或对象存储中的文件，可以被组织成表：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>database</span></span>
<span class="line"><span>  -&gt; table</span></span>
<span class="line"><span>  -&gt; partition</span></span>
<span class="line"><span>  -&gt; file</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>分区表是 Hive 离线数仓的关键能力。例如按日期分区：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ods_orders/dt=2026-04-01/</span></span>
<span class="line"><span>ods_orders/dt=2026-04-02/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>查询某天数据时，只扫描对应分区。</p><p>Hive 的核心判断是：</p><blockquote><p>Hive 把文件系统上的大规模数据组织成 SQL 可查询的数仓表。</p></blockquote><p>它不适合低延迟交互分析，但适合离线数仓、历史归档和大规模批处理。</p><h3 id="_7-2-spark-大规模数据计算引擎" tabindex="-1">7.2 Spark：大规模数据计算引擎 <a class="header-anchor" href="#_7-2-spark-大规模数据计算引擎" aria-label="Permalink to &quot;7.2 Spark：大规模数据计算引擎&quot;">​</a></h3><p>Spark 解决的是分布式计算问题。</p><p>它不仅能跑 SQL，也能处理复杂 ETL、机器学习预处理、数据清洗和批量特征计算。</p><p>核心概念包括：</p><ul><li>Spark Core。</li><li>Spark SQL。</li><li>DataFrame / Dataset。</li><li>Driver / Executor。</li><li>Partition。</li><li>Job / Stage / Task。</li><li>Shuffle。</li><li>Cache。</li><li>Broadcast Join。</li><li>Sort Merge Join。</li><li>AQE。</li></ul><p>Spark 的执行可以粗略理解为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提交任务</span></span>
<span class="line"><span>  -&gt; Driver 生成执行计划</span></span>
<span class="line"><span>  -&gt; 拆成 Job / Stage / Task</span></span>
<span class="line"><span>  -&gt; Executor 并行处理数据分区</span></span>
<span class="line"><span>  -&gt; Shuffle 重新分布数据</span></span>
<span class="line"><span>  -&gt; 输出结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Spark 的关键难点是 Shuffle。</p><p>当数据需要按 key 重新分组、聚合或 JOIN 时，数据会跨节点移动。Shuffle 通常意味着网络、磁盘、序列化、排序和内存压力。</p><p>所以 Spark SQL 优化不是只看 SQL 写法，还要看：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据分区是否合理</span></span>
<span class="line"><span>JOIN 两边数据量多大</span></span>
<span class="line"><span>是否可以广播小表</span></span>
<span class="line"><span>是否发生数据倾斜</span></span>
<span class="line"><span>是否反复读取相同数据</span></span>
<span class="line"><span>文件数量是否过多</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Spark 的核心判断是：</p><blockquote><p>Spark 把单机无法舒适完成的大规模历史计算，拆成分布式任务并行执行。</p></blockquote><h3 id="_7-3-trino-presto-跨源交互式分析" tabindex="-1">7.3 Trino / Presto：跨源交互式分析 <a class="header-anchor" href="#_7-3-trino-presto-跨源交互式分析" aria-label="Permalink to &quot;7.3 Trino / Presto：跨源交互式分析&quot;">​</a></h3><p>Trino 和 Presto 的核心定位是分布式 SQL 查询引擎。</p><p>它们通过 Connector 连接不同数据源：</p><ul><li>Hive。</li><li>Iceberg。</li><li>PostgreSQL。</li><li>MySQL。</li><li>Kafka。</li><li>Elasticsearch。</li><li>其他对象存储或数据系统。</li></ul><p>核心组件包括：</p><ul><li>Coordinator。</li><li>Worker。</li><li>Catalog。</li><li>Schema。</li><li>Connector。</li></ul><p>Trino 的价值在于跨源查询和交互式分析：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    u</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    SUM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">o</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">total_amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> gmv</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> postgresql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sales</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.orders o</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> hive</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dim</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.dim_user u</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> o</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">user_id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> u</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">user_id</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GROUP BY</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> u</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这类能力让分析人员可以通过统一 SQL 查询多个系统。</p><p>但跨源查询也有边界。数据下推、网络传输、源系统压力、JOIN 数据量、权限一致性，都会影响可用性。</p><p>Trino 的核心判断是：</p><blockquote><p>Trino 不是存储系统，而是把多个数据源统一到 SQL 查询层的分析引擎。</p></blockquote><h3 id="批处理与-postgresql-的差异" tabindex="-1">批处理与 PostgreSQL 的差异 <a class="header-anchor" href="#批处理与-postgresql-的差异" aria-label="Permalink to &quot;批处理与 PostgreSQL 的差异&quot;">​</a></h3><p>PostgreSQL 适合业务库和中小规模分析。</p><p>批处理系统适合大规模历史数据加工。</p><p>差异包括：</p><table tabindex="0"><thead><tr><th>维度</th><th>PostgreSQL</th><th>Hive / Spark / Trino</th></tr></thead><tbody><tr><td>主要任务</td><td>业务交易、中小查询</td><td>大规模历史计算、跨源分析</td></tr><tr><td>存储形态</td><td>数据库内部存储</td><td>HDFS / Object Storage / 表格式</td></tr><tr><td>计算方式</td><td>单机为主</td><td>分布式</td></tr><tr><td>查询延迟</td><td>低延迟短查询</td><td>批量或交互式分析</td></tr><tr><td>典型数据</td><td>当前业务数据</td><td>历史明细、数仓、湖仓</td></tr></tbody></table><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>批处理位于数据平台的离线计算层。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL / 日志 / 外部文件</span></span>
<span class="line"><span>  -&gt; ETL / CDC</span></span>
<span class="line"><span>  -&gt; ODS / Lake</span></span>
<span class="line"><span>  -&gt; Hive Metastore / 表格式</span></span>
<span class="line"><span>  -&gt; Spark / Hive SQL 批量加工</span></span>
<span class="line"><span>  -&gt; DWD / DWS / ADS</span></span>
<span class="line"><span>  -&gt; Trino / BI / 特征平台 / AI 数据准备</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>它承接第 6 章的数据链路，负责把进入平台的数据加工成可复用资产。它也为后续章节做铺垫：第 8 章实时处理解决“不能等到明天”的问题，第 9 章 OLAP 数据库解决“结果如何被快速查询”的问题，第 12 章湖仓把批处理和多引擎访问建立在开放表格式之上。</p><p>从 PostgreSQL 视角看，批处理不是替代业务库，而是把业务库不适合长期承担的历史扫描、跨域 JOIN、全量回算和特征批量生成转移到分布式分析体系。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>假设经营看板每天早上 8 点前要展示昨天的销售指标。</p><p>批处理链路可以设计为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>00:30 同步 PostgreSQL orders / order_items / payments 到 ODS 分区</span></span>
<span class="line"><span>01:00 清洗生成 dwd_order_payment_detail</span></span>
<span class="line"><span>02:00 关联 dim_user / dim_product / dim_channel</span></span>
<span class="line"><span>03:00 生成 dws_product_daily、dws_channel_daily、dws_user_daily</span></span>
<span class="line"><span>04:00 生成 ads_sales_dashboard</span></span>
<span class="line"><span>05:00 运行质量检查和对账</span></span>
<span class="line"><span>08:00 BI 看板展示</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个链路有几个关键判断：</p><ul><li>ODS 按业务日期或同步日期分区，方便重跑和追溯。</li><li>DWD 明确订单支付明细的一行粒度，避免 JOIN 后重复计算。</li><li>DWS 沉淀公共汇总，避免每个报表重复扫描明细。</li><li>ADS 面向具体看板，允许为展示便利做冗余。</li><li>如果某天任务失败，可以只重跑受影响分区，而不是重算全部历史。</li></ul><p>批处理的价值就在这里：它把复杂历史加工变成可调度、可重跑、可检查的工程流程。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：Hive、Spark、Trino 都是同一种东西。</strong></p><p>Hive 更像离线数仓 SQL 和元数据体系，Spark 是通用分布式计算引擎，Trino 是跨源交互式 SQL 查询引擎。</p><p><strong>误区二：Spark 一定比 PostgreSQL 快。</strong></p><p>小数据、点查、事务查询，PostgreSQL 更合适。Spark 的优势在大规模并行计算，不在所有查询都快。</p><p><strong>误区三：批处理只要能跑完就行。</strong></p><p>批处理还要支持依赖、重跑、幂等、质量校验、资源成本和产物可追溯。</p><p><strong>误区四：分布式计算一定比单机快。</strong></p><p>小数据、点查、短查询和强事务场景下，分布式系统的调度、网络和 Shuffle 成本可能反而更高。批处理的优势在大规模历史吞吐，不在所有查询延迟。</p><p><strong>误区五：能跨源查询就可以随意 JOIN。</strong></p><p>Trino 可以连接多个系统，但跨源 JOIN 可能造成大量网络传输和源库压力。跨源查询适合探索和轻量联邦分析，稳定报表通常仍应沉淀到数仓或湖仓模型中。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>设计一个每日订单数仓批处理任务：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL orders / order_items / payments</span></span>
<span class="line"><span>  -&gt; ODS</span></span>
<span class="line"><span>  -&gt; DWD 订单明细</span></span>
<span class="line"><span>  -&gt; DWS 商品日汇总</span></span>
<span class="line"><span>  -&gt; ADS 销售看板</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>要求说明：</p><ul><li>哪些数据按天分区。</li><li>哪些任务可以重跑。</li><li>哪些 JOIN 可能产生 Shuffle。</li><li>哪些维度表适合广播。</li><li>输出哪些质量检查。</li></ul><p>补充要求：</p><ul><li>画出任务 DAG。</li><li>指出每个任务输入分区和输出分区。</li><li>说明如果 <code>dim_product</code> 修正了历史类目，哪些 DWS / ADS 表需要回填。</li><li>设计至少 3 个质量检查，例如行数波动、主键唯一、金额对账。</li><li>估算最容易发生 Shuffle 的步骤，并说明如何优化。</li></ul><p>示例 DAG：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ods_orders</span></span>
<span class="line"><span>  -&gt; dwd_order_payment_detail</span></span>
<span class="line"><span>ods_order_items</span></span>
<span class="line"><span>  -&gt; dwd_order_payment_detail</span></span>
<span class="line"><span>ods_payments</span></span>
<span class="line"><span>  -&gt; dwd_order_payment_detail</span></span>
<span class="line"><span>dim_product</span></span>
<span class="line"><span>  -&gt; dws_product_daily</span></span>
<span class="line"><span>dwd_order_payment_detail</span></span>
<span class="line"><span>  -&gt; dws_product_daily</span></span>
<span class="line"><span>  -&gt; dws_channel_daily</span></span>
<span class="line"><span>  -&gt; ads_sales_dashboard</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>批处理系统让数据平台能够稳定加工大规模历史数据。</p><p>Hive 组织离线数仓表，Spark 执行大规模计算，Trino 提供跨源交互式查询。</p><p>下一章进入实时数据处理。</p><p>因为很多业务问题不能等到明天再回答，它们需要在事件发生时就被捕获、计算和展示。</p>`,91))])}const E=e(o,[["render",c]]);export{v as __pageData,E as default};
